export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Record<string, unknown>[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: Record<string, unknown>) => boolean): Record<string, unknown>[];
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<unknown, Record<string, unknown>[]>;
}

interface ParsedRow {
  row: number;
  values: string[];
}

const DEFAULT_DELIMITER = ',';
const DEFAULT_QUOTE = '"';
const DEFAULT_LINE_SEPARATOR = '\n';

function coerceValue(raw: string): unknown {
  const trimmed = raw.trim();
  if (raw === '') {
    return null;
  }

  if (trimmed.length === 0 && raw.length > 0) {
    // keep whitespace-only strings as-is
    return raw;
  }

  const lower = trimmed.toLowerCase();
  if (lower === 'null') {
    return null;
  }

  if (lower === 'true') {
    return true;
  }

  if (lower === 'false') {
    return false;
  }

  const numberPattern = /^[+-]?(?:\d+|\d*\.\d+)$/;
  if (numberPattern.test(trimmed)) {
    return Number(trimmed);
  }

  return raw;
}

export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const delimiterValue = options?.delimiter && options.delimiter.length > 0 ? options.delimiter : DEFAULT_DELIMITER;
  const quoteValue = options?.quote && options.quote.length > 0 ? options.quote[0] : DEFAULT_QUOTE;
  const lineSeparatorValue = options?.lineSeparator && options.lineSeparator.length > 0 ? options.lineSeparator : DEFAULT_LINE_SEPARATOR;

  let workingInput = input ?? '';
  if (lineSeparatorValue === DEFAULT_LINE_SEPARATOR) {
    workingInput = workingInput.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
  }

  const parsedRows: ParsedRow[] = [];
  const errors: CSVError[] = [];
  const delimLen = delimiterValue.length;
  const lineSepLen = lineSeparatorValue.length;

  let currentRow: string[] = [];
  let currentValue = '';
  let insideQuotes = false;
  let currentRowNumber = 1;
  let i = 0;

  while (i < workingInput.length) {
    const remaining = workingInput.length - i;
    const char = workingInput[i];

    if (char === quoteValue) {
      if (insideQuotes) {
        const nextChar = workingInput[i + 1];
        if (nextChar === quoteValue) {
          currentValue += quoteValue;
          i += 2;
          continue;
        }
        insideQuotes = false;
        i += 1;
        continue;
      }
      insideQuotes = true;
      i += 1;
      continue;
    }

    if (!insideQuotes && lineSepLen > 0 && workingInput.startsWith(lineSeparatorValue, i)) {
      currentRow.push(currentValue);
      parsedRows.push({ row: currentRowNumber, values: currentRow });
      currentRowNumber += 1;
      currentRow = [];
      currentValue = '';
      i += lineSepLen;
      continue;
    }

    if (!insideQuotes && delimLen > 0 && workingInput.startsWith(delimiterValue, i)) {
      currentRow.push(currentValue);
      currentValue = '';
      i += delimLen;
      continue;
    }

    currentValue += char;
    i += 1;
  }

  if (insideQuotes) {
    errors.push({ row: currentRowNumber, message: 'Unterminated quoted field' });
  } else if (currentValue !== '' || currentRow.length > 0) {
    currentRow.push(currentValue);
    parsedRows.push({ row: currentRowNumber, values: currentRow });
  }

  if (parsedRows.length === 0) {
    const emptyResult: CSVResult = {
      rows: [],
      headers: [],
      errors,
      filter: () => [],
      sum: () => 0,
      average: () => 0,
      count: () => 0,
      groupBy: () => new Map(),
    };
    return emptyResult;
  }

  const headerRow = parsedRows[0];
  const headers = headerRow.values.slice();
  const populatedRows: Record<string, unknown>[] = [];

  for (let idx = 1; idx < parsedRows.length; idx += 1) {
    const parsed = parsedRows[idx];
    if (parsed.values.length !== headers.length) {
      errors.push({
        row: parsed.row,
        message: `Expected ${headers.length} columns but found ${parsed.values.length}`,
      });
      continue;
    }

    const rowObj: Record<string, unknown> = {};
    for (let col = 0; col < headers.length; col += 1) {
      const header = headers[col];
      rowObj[header] = coerceValue(parsed.values[col]);
    }
    populatedRows.push(rowObj);
  }

  const result: CSVResult = {
    rows: populatedRows,
    headers,
    errors,
    filter: (predicate) => populatedRows.filter(predicate),
    sum: (column) =>
      populatedRows.reduce((acc, row) => {
        const value = row[column];
        if (typeof value === 'number') {
          return acc + value;
        }
        return acc;
      }, 0),
    average: (column) => {
      let total = 0;
      let count = 0;
      for (const row of populatedRows) {
        const value = row[column];
        if (typeof value === 'number') {
          total += value;
          count += 1;
        }
      }
      return count === 0 ? 0 : total / count;
    },
    count: () => populatedRows.length,
    groupBy: (column) => {
      const map = new Map<unknown, Record<string, unknown>[]>();
      for (const row of populatedRows) {
        const key = row[column];
        const existing = map.get(key);
        if (existing) {
          existing.push(row);
        } else {
          map.set(key, [row]);
        }
      }
      return map;
    },
  };

  return result;
}

import { parseCSV } from './csv-parser';

const assert = (condition: boolean, message?: string) => {
  if (!condition) {
    throw new Error(message || 'Assertion failed');
  }
};

const tests: Array<{ name: string; run: () => void }> = [
  {
    name: 'basic parsing',
    run: () => {
      const input = 'name,age\nAlice,30\nBob,25';
      const result = parseCSV(input);
      assert(result.headers.length === 2, 'headers should contain two columns');
      assert(result.rows.length === 2, 'should parse two rows');
      const first = result.rows[0];
      assert(first['name'] === 'Alice', 'first row name should match');
      assert(first['age'] === 30, 'age should be coerced to number');
      assert(result.errors.length === 0, 'should have no errors for valid input');
    },
  },
  {
    name: 'quoted fields with commas',
    run: () => {
      const input = 'name,address\n"John Doe","123 Main St, Apt 4"\n"Jane","456 Oak St, Apt 2"';
      const result = parseCSV(input);
      const first = result.rows[0];
      const second = result.rows[1];
      assert(first['address'] === '123 Main St, Apt 4');
      assert(second['name'] === 'Jane');
    },
  },
  {
    name: 'escaped quotes',
    run: () => {
      const input = 'quote\n"She said ""Hello"" today"';
      const result = parseCSV(input);
      assert(result.rows.length === 1);
      assert(result.rows[0]['quote'] === 'She said "Hello" today');
    },
  },
  {
    name: 'custom delimiters and separators',
    run: () => {
      const input = 'name|age|city<<Alice|30|New York<<Bob|25|San Francisco';
      const result = parseCSV(input, { delimiter: '|', lineSeparator: '<<' });
      assert(result.rows.length === 2, 'should parse rows with custom separator');
      assert(result.rows[1]['city'] === 'San Francisco');
    },
  },
  {
    name: 'type coercion for basics',
    run: () => {
      const input = ['value', '42', '3.14', 'true', 'FALSE', 'null', 'NULL', '', 'hello', '  123  '].join('\n');
      const result = parseCSV(input);
      const values = result.rows.map((row) => row['value']);
      const expected = [42, 3.14, true, false, null, null, null, 'hello', 123];
      assert(values.length === expected.length, 'should have matching row count for type test');
      for (let i = 0; i < expected.length; i += 1) {
        assert(values[i] === expected[i], `value at index ${i} should match expected type`);
      }
    },
  },
  {
    name: 'malformed row errors',
    run: () => {
      const input = 'name,age\nAlice,30\nBob\nCarol,25,NY';
      const result = parseCSV(input);
      assert(result.errors.length === 2, 'should collect errors for malformed rows');
      const hasMissing = result.errors.some((err) => err.row === 3);
      const hasExtra = result.errors.some((err) => err.row === 4);
      assert(hasMissing, 'missing column error should reference row 3');
      assert(hasExtra, 'extra column error should reference row 4');
      assert(result.rows.length === 1, 'valid rows should still be returned');
    },
  },
  {
    name: 'filter functionality',
    run: () => {
      const input = 'name,age\nAlice,30\nBob,22\nCarol,35';
      const result = parseCSV(input);
      const filtered = result.filter((row) => {
        const age = row['age'];
        return typeof age === 'number' && age > 30;
      });
      assert(filtered.length === 1, 'filter should return only rows matching predicate');
      assert(filtered[0]['name'] === 'Carol');
    },
  },
  {
    name: 'aggregation helpers',
    run: () => {
      const input = 'name,age,city\nAlice,30,NY\nBob,25,NY\nCarol,40,LA\nDave,35,LA';
      const result = parseCSV(input);
      assert(result.sum('age') === 130, 'sum should total numeric column');
      const avg = result.average('age');
      assert(Math.abs(avg - 32.5) < 1e-9, 'average should compute numeric mean');
      assert(result.count() === 4, 'count should reflect number of rows');
      const grouped = result.groupBy('city');
      assert(grouped.get('NY')?.length === 2, 'groupBy should bucket rows');
      assert(grouped.get('LA')?.length === 2, 'groupBy should bucket rows');
    },
  },
  {
    name: 'empty input and single entry edge cases',
    run: () => {
      const empty = parseCSV('');
      assert(empty.headers.length === 0, 'empty CSV should have no headers');
      assert(empty.rows.length === 0, 'empty CSV should have no rows');
      assert(empty.sum('anything') === 0, 'sum should be safe on empty data');
      assert(empty.average('anything') === 0, 'average should be safe on empty data');
      assert(empty.count() === 0, 'count should be zero when no data');

      const singleColumn = parseCSV('flag\ntrue');
      assert(singleColumn.headers.length === 1, 'single column header preserved');
      assert(singleColumn.rows.length === 1, 'single column should parse one row');
      assert(singleColumn.rows[0]['flag'] === true);

      const singleRow = parseCSV('only\nvalue');
      assert(singleRow.count() === 1, 'single data row should be present');
      assert(singleRow.rows[0]['only'] === 'value');
    },
  },
  {
    name: 'large fields handled',
    run: () => {
      const longValue = 'x'.repeat(12000);
      const input = `content\n"${longValue}"`;
      const result = parseCSV(input);
      assert(result.rows.length === 1, 'should parse row with large field');
      assert(result.rows[0]['content'] === longValue, 'value should match large payload');
    },
  },
];

for (const test of tests) {
  try {
    test.run();
    console.log(`✅ ${test.name}`);
  } catch (error) {
    console.error(`❌ ${test.name}`);
    throw error;
  }
}

console.log('All tests passed!');

