export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Record<string, unknown>[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: Record<string, unknown>) => boolean): Record<string, unknown>[];
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<unknown, Record<string, unknown>[]>;
}

interface ParsedRow {
  row: number;
  values: string[];
}

const DEFAULT_DELIMITER = ',';
const DEFAULT_QUOTE = '"';
const DEFAULT_LINE_SEPARATOR = '\n';

function coerceValue(raw: string): unknown {
  const trimmed = raw.trim();
  if (raw === '') {
    return null;
  }

  if (trimmed.length === 0 && raw.length > 0) {
    // keep whitespace-only strings as-is
    return raw;
  }

  const lower = trimmed.toLowerCase();
  if (lower === 'null') {
    return null;
  }

  if (lower === 'true') {
    return true;
  }

  if (lower === 'false') {
    return false;
  }

  const numberPattern = /^[+-]?(?:\d+|\d*\.\d+)$/;
  if (numberPattern.test(trimmed)) {
    return Number(trimmed);
  }

  return raw;
}

export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const delimiterValue = options?.delimiter && options.delimiter.length > 0 ? options.delimiter : DEFAULT_DELIMITER;
  const quoteValue = options?.quote && options.quote.length > 0 ? options.quote[0] : DEFAULT_QUOTE;
  const lineSeparatorValue = options?.lineSeparator && options.lineSeparator.length > 0 ? options.lineSeparator : DEFAULT_LINE_SEPARATOR;

  let workingInput = input ?? '';
  if (lineSeparatorValue === DEFAULT_LINE_SEPARATOR) {
    workingInput = workingInput.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
  }

  const parsedRows: ParsedRow[] = [];
  const errors: CSVError[] = [];
  const delimLen = delimiterValue.length;
  const lineSepLen = lineSeparatorValue.length;

  let currentRow: string[] = [];
  let currentValue = '';
  let insideQuotes = false;
  let currentRowNumber = 1;
  let i = 0;

  while (i < workingInput.length) {
    const char = workingInput[i];

    if (char === quoteValue) {
      if (insideQuotes) {
        const nextChar = workingInput[i + 1];
        if (nextChar === quoteValue) {
          currentValue += quoteValue;
          i += 2;
          continue;
        }
        insideQuotes = false;
        i += 1;
        continue;
      }
      insideQuotes = true;
      i += 1;
      continue;
    }

    if (!insideQuotes && lineSepLen > 0 && workingInput.startsWith(lineSeparatorValue, i)) {
      currentRow.push(currentValue);
      parsedRows.push({ row: currentRowNumber, values: currentRow });
      currentRowNumber += 1;
      currentRow = [];
      currentValue = '';
      i += lineSepLen;
      continue;
    }

    if (!insideQuotes && delimLen > 0 && workingInput.startsWith(delimiterValue, i)) {
      currentRow.push(currentValue);
      currentValue = '';
      i += delimLen;
      continue;
    }

    currentValue += char;
    i += 1;
  }

  if (insideQuotes) {
    errors.push({ row: currentRowNumber, message: 'Unterminated quoted field' });
  } else if (currentValue !== '' || currentRow.length > 0) {
    currentRow.push(currentValue);
    parsedRows.push({ row: currentRowNumber, values: currentRow });
  }

  if (parsedRows.length === 0) {
    const emptyResult: CSVResult = {
      rows: [],
      headers: [],
      errors,
      filter: () => [],
      sum: () => 0,
      average: () => 0,
      count: () => 0,
      groupBy: () => new Map(),
    };
    return emptyResult;
  }

  const headerRow = parsedRows[0];
  const headers = headerRow.values.slice();
  const populatedRows: Record<string, unknown>[] = [];

  for (let idx = 1; idx < parsedRows.length; idx += 1) {
    const parsed = parsedRows[idx];
    if (parsed.values.length !== headers.length) {
      errors.push({
        row: parsed.row,
        message: `Expected ${headers.length} columns but found ${parsed.values.length}`,
      });
      continue;
    }

    const rowObj: Record<string, unknown> = {};
    for (let col = 0; col < headers.length; col += 1) {
      const header = headers[col];
      rowObj[header] = coerceValue(parsed.values[col]);
    }
    populatedRows.push(rowObj);
  }

  const result: CSVResult = {
    rows: populatedRows,
    headers,
    errors,
    filter: (predicate) => populatedRows.filter(predicate),
    sum: (column) =>
      populatedRows.reduce((acc, row) => {
        const value = row[column];
        if (typeof value === 'number') {
          return acc + value;
        }
        return acc;
      }, 0),
    average: (column) => {
      let total = 0;
      let count = 0;
      for (const row of populatedRows) {
        const value = row[column];
        if (typeof value === 'number') {
          total += value;
          count += 1;
        }
      }
      return count === 0 ? 0 : total / count;
    },
    count: () => populatedRows.length,
    groupBy: (column) => {
      const map = new Map<unknown, Record<string, unknown>[]>();
      for (const row of populatedRows) {
        const key = row[column];
        const existing = map.get(key);
        if (existing) {
          existing.push(row);
        } else {
          map.set(key, [row]);
        }
      }
      return map;
    },
  };

  return result;
}
